    let minDiff = Infinity;

    // Since we are looking for the minimum absolute difference, 
    // it is beneficial to sort both lists of indices (they are naturally sorted if we iterate sequentially, 
    // but for clarity and robustness in general, we can ensure they are sorted).
    // Since we collected them by iterating i from 0 to N-1, they are already sorted.

    const ones = indicesOfOne;
    const twos = indicesOfTwo;

    // A two-pointer approach is efficient here, similar to merging two sorted arrays.
    let p1 = 0;
    let p2 = 0;

    while (p1 < ones.length && p2 < twos.length) {
        const i = ones[p1];
        const j = twos[p2];

        // Calculate current difference
        const diff = Math.abs(i - j);

        // Update minimum difference
        minDiff = Math.min(minDiff, diff);

        // Advance the pointer pointing to the smaller index
        // This is the greedy step: by advancing the smaller index, we are trying to bring 
        // the next candidate closer to the other list's current element, minimizing the next difference.
        if (i < j) {
            p1++;
        } else {
            p2++;
        }
    }

    return minDiff;
}
